// Module patterns
// Singleton pattern
let instance = null;

export class Logger {
  constructor() {
    if (!instance) {
      instance = this;
      this.logs = [];
    }
    return instance;
  }

  log(message) {
    const timestamp = new Date().toISOString();
    this.logs.push({ message, timestamp });
    console.log(`[${timestamp}] ${message}`);
  }

  getLogs() {
    return this.logs;
  }
}

// Factory pattern
export function createLogger(type) {
  switch(type) {
    case 'console':
      return {
        log: (msg) => console.log(msg),
        error: (msg) => console.error(msg)
      };
    case 'file':
      return {
        log: (msg) => console.log('File log:', msg),
        error: (msg) => console.error('File error:', msg)
      };
    default:
      throw new Error('Unknown logger type');
  }
}

