// Service Worker for caching
// service-worker.js
const CACHE_NAME = 'v1';
const urlsToCache = [
  '/',
  '/index.html',
  '/styles.css',
  '/app.js',
  '/manifest.json'
];

self.addEventListener('install', event => {
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then(cache => cache.addAll(urlsToCache))
  );
});

self.addEventListener('fetch', event => {
  event.respondWith(
    caches.match(event.request)
      .then(response => {
        if (response) {
          return response;
        }

        return fetch(event.request)
          .then(response => {
            if (!response || response.status !== 200 || response.type !== 'basic') {
              return response;
            }

            const responseToCache = response.clone();

            caches.open(CACHE_NAME)
              .then(cache => {
                cache.put(event.request, responseToCache);
              });

            return response;
          });
      })
  );
});

// Performance monitoring
function measurePerformance() {
  // First Contentful Paint
  const fcp = performance.getEntriesByName('first-contentful-paint')[0];
  console.log('FCP:', fcp.startTime);

  // Largest Contentful Paint
  const lcp = performance.getEntriesByName('largest-contentful-paint')[0];
  console.log('LCP:', lcp.startTime);

  // Cumulative Layout Shift
  let cls = 0;
  const layoutShiftEntries = performance.getEntriesByType('layout-shift');
  layoutShiftEntries.forEach(entry => {
    if (!entry.hadRecentInput) {
      cls += entry.value;
    }
  });
  console.log('CLS:', cls);

  // Memory usage
  if (performance.memory) {
    console.log('Memory used:', performance.memory.usedJSHeapSize);
    console.log('Memory limit:', performance.memory.jsHeapSizeLimit);
  }
}

// Request Animation Frame for smooth animations
function animateElement(element) {
  let startTime = null;

  function step(timestamp) {
    if (!startTime) startTime = timestamp;

    const progress = timestamp - startTime;
    const position = Math.min(progress / 1000, 1); // 1 second animation

    // Update element position
    element.style.transform = `translateX(${position * 100}px)`;

    if (position < 1) {
      requestAnimationFrame(step);
    }
  }

  requestAnimationFrame(step);
}

// Input validation and sanitization
function validateInput(input) {
  // Trim whitespace
  input = input.trim();

  // Prevent empty strings
  if (!input) {
    throw new Error('Input cannot be empty');
  }

  // Maximum length
  if (input.length > 255) {
    throw new Error('Input too long');
  }

  // Allow only alphanumeric and basic punctuation
  if (!/^[a-zA-Z0-9\s.,!?@'-]+$/.test(input)) {
    throw new Error('Invalid characters in input');
  }

  return input;
}

// HTML escaping to prevent XSS
function escapeHTML(text) {
  const map = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#x27;',
    '/': '&#x2F;'
  };

  return String(text).replace(/[&<>"'/]/g, char => map[char]);
}

// Using DOMPurify for HTML sanitization
// <script src="https://cdnjs.cloudflare.com/ajax/libs/dompurify/3.0.0/purify.min.js"></script>
function sanitizeHTML(dirtyHTML) {
  return DOMPurify.sanitize(dirtyHTML, {
    ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'p', 'br'],
    ALLOWED_ATTR: ['href', 'title'],
    ALLOWED_URI_REGEXP: /^(https?:\/\/)?[\w\-]+(\.[\w\-]+)+[/#?]?.*$/,
    FORBID_TAGS: ['script', 'style', 'iframe', 'object', 'embed'],
    FORBID_ATTR: ['onclick', 'onerror', 'onload']
  });
}

