// WebSocket server with Node.js and ws library
const WebSocket = require('ws');
const http = require('http');

// Create HTTP server
const server = http.createServer((req, res) => {
  res.writeHead(200, { 'Content-Type': 'text/plain' });
  res.end('WebSocket server is running');
});

// Create WebSocket server
const wss = new WebSocket.Server({ server });

// Store connected clients
const clients = new Map();

wss.on('connection', (ws, request) => {
  const clientId = generateClientId();
  const clientInfo = {
    id: clientId,
    ws,
    ip: request.socket.remoteAddress,
    connectedAt: new Date()
  };

  clients.set(clientId, clientInfo);

  console.log(`Client connected: ${clientId}`);

  // Send welcome message
  ws.send(JSON.stringify({
    type: 'welcome',
    payload: {
      clientId,
      message: 'Connected to WebSocket server',
      timestamp: new Date().toISOString()
    }
  }));

  // Broadcast user joined
  broadcast({
    type: 'user-joined',
    payload: { clientId, timestamp: new Date().toISOString() }
  }, clientId);

  // Handle messages from client
  ws.on('message', (data) => {
    try {
      const message = JSON.parse(data);
      handleMessage(clientId, message);
    } catch (error) {
      console.error('Error parsing message:', error);
      ws.send(JSON.stringify({
        type: 'error',
        payload: { message: 'Invalid message format' }
      }));
    }
  });

  // Handle disconnection
  ws.on('close', () => {
    clients.delete(clientId);
    console.log(`Client disconnected: ${clientId}`);

    // Broadcast user left
    broadcast({
      type: 'user-left',
      payload: { clientId, timestamp: new Date().toISOString() }
    });
  });

  // Handle errors
  ws.on('error', (error) => {
    console.error(`WebSocket error for client ${clientId}:`, error);
  });
});

// Message handler
function handleMessage(clientId, message) {
  const { type, payload } = message;
  const clientInfo = clients.get(clientId);

  if (!clientInfo) return;

  switch (type) {
    case 'chat-message':
      // Validate message
      if (!payload.text || payload.text.trim() === '') {
        clientInfo.ws.send(JSON.stringify({
          type: 'error',
          payload: { message: 'Message cannot be empty' }
        }));
        return;
      }

      // Add metadata
      const chatMessage = {
        ...payload,
        clientId,
        messageId: generateMessageId(),
        timestamp: new Date().toISOString()
      };

      // Broadcast to all clients
      broadcast({
        type: 'chat-message',
        payload: chatMessage
      });
      break;

    case 'ping':
      clientInfo.ws.send(JSON.stringify({
        type: 'pong',
        payload: { timestamp: new Date().toISOString() }
      }));
      break;

    case 'private-message':
      const { recipientId, text } = payload;
      sendPrivateMessage(clientId, recipientId, text);
      break;

    default:
      console.log(`Unknown message type: ${type}`);
  }
}

// Broadcast to all clients except sender
function broadcast(message, excludeClientId = null) {
  const data = JSON.stringify(message);

  clients.forEach((clientInfo, clientId) => {
    if (clientId !== excludeClientId && clientInfo.ws.readyState === WebSocket.OPEN) {
      clientInfo.ws.send(data);
    }
  });
}

// Send private message
function sendPrivateMessage(senderId, recipientId, text) {
  const sender = clients.get(senderId);
  const recipient = clients.get(recipientId);

  if (!sender || !recipient) {
    sender.ws.send(JSON.stringify({
      type: 'error',
      payload: { message: 'Recipient not found' }
    }));
    return;
  }

  const privateMessage = {
    senderId,
    recipientId,
    text,
    messageId: generateMessageId(),
    timestamp: new Date().toISOString()
  };

  // Send to recipient
  recipient.ws.send(JSON.stringify({
    type: 'private-message',
    payload: privateMessage
  }));

  // Send confirmation to sender
  sender.ws.send(JSON.stringify({
    type: 'message-sent',
    payload: privateMessage
  }));
}

// Utility functions
function generateClientId() {
  return 'client_' + Math.random().toString(36).substr(2, 9);
}

function generateMessageId() {
  return 'msg_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);
}

