// Real-time chat application example
class ChatApplication {
  constructor() {
    this.wsClient = new WebSocketClient('wss://api.example.com/ws');
    this.messages = [];
    this.users = new Map();
    this.currentUser = null;

    this.init();
  }

  init() {
    this.wsClient.connect();
    this.setupEventListeners();
    this.loadPreviousMessages();
  }

  setupEventListeners() {
    // Connection events
    this.wsClient.onConnectionChange((connected) => {
      this.updateConnectionStatus(connected);
    });

    // Message events
    this.wsClient.on('chat-message', (message) => {
      this.addMessage(message);
    });

    this.wsClient.on('user-joined', (user) => {
      this.addUser(user);
      this.showSystemMessage(`${user.name} joined the chat`);
    });

    this.wsClient.on('user-left', (user) => {
      this.removeUser(user.id);
      this.showSystemMessage(`${user.name} left the chat`);
    });

    this.wsClient.on('user-list', (users) => {
      this.updateUserList(users);
    });

    this.wsClient.on('typing', (data) => {
      this.showTypingIndicator(data.userId, data.isTyping);
    });
  }

  sendMessage(text) {
    if (!text.trim()) return;

    const message = {
      text,
      userId: this.currentUser.id,
      username: this.currentUser.name,
      timestamp: Date.now()
    };

    this.wsClient.send('chat-message', message);
    this.addMessage({ ...message, isOwn: true });
  }

  sendTypingIndicator(isTyping) {
    this.wsClient.send('typing', {
      userId: this.currentUser.id,
      isTyping
    });
  }

  addMessage(message) {
    this.messages.push(message);
    this.renderMessage(message);

    // Keep only last 100 messages
    if (this.messages.length > 100) {
      this.messages.shift();
    }
  }

  addUser(user) {
    this.users.set(user.id, user);
    this.renderUser(user);
  }

  updateConnectionStatus(connected) {
    const statusElement = document.getElementById('connection-status');
    if (statusElement) {
      statusElement.textContent = connected ? 'Connected' : 'Disconnected';
      statusElement.className = connected ? 'connected' : 'disconnected';
    }
  }

  loadPreviousMessages() {
    // Load messages from localStorage or API
    const savedMessages = localStorage.getItem('chat-messages');
    if (savedMessages) {
      const messages = JSON.parse(savedMessages);
      messages.forEach(message => this.addMessage(message));
    }
  }

  renderMessage(message) {
    const messagesContainer = document.getElementById('messages');
    if (!messagesContainer) return;

    const messageElement = document.createElement('div');
    messageElement.className = `message ${message.isOwn ? 'own' : 'other'}`;

    const time = new Date(message.timestamp).toLocaleTimeString();

    messageElement.innerHTML = `
      <div class="message-header">
        <span class="username">${message.username}</span>
        <span class="timestamp">${time}</span>
      </div>
      <div class="message-content">${this.escapeHTML(message.text)}</div>
    `;

    messagesContainer.appendChild(messageElement);
    messagesContainer.scrollTop = messagesContainer.scrollHeight;
  }

  escapeHTML(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }
}

