import React from 'react';
import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useWishlist } from '../context/WishlistContext';
import { Star, ShoppingCart, Heart } from 'lucide-react';

const ProductCard = ({ product }) => {
  const { addToCart } = useCart();
  const { addToWishlist, removeFromWishlist, isInWishlist } = useWishlist();

  const finalPrice = product.discountPrice || product.price;
  const discountPercent = product.discountPrice 
    ? Math.round(((product.price - product.discountPrice) / product.price) * 100)
    : 0;

  const handleAddToCart = () => {
    addToCart({
      id: product._id,
      name: product.name,
      price: finalPrice,
      image: product.images[0]?.url,
      stock: product.stock,
      quantity: 1
    });
  };

  const handleWishlistToggle = () => {
    if (isInWishlist(product._id)) {
      removeFromWishlist(product._id);
    } else {
      addToWishlist(product);
    }
  };

  return (
    <div className="product-card">
      <div className="product-image">
        <Link to={`/product/${product._id}`}>
          <img
            src={product.images[0]?.url || '/placeholder.jpg'}
            alt={product.images[0]?.altText || product.name}
            loading="lazy"
          />
        </Link>

        {discountPercent > 0 && (
          <span className="discount-badge">-{discountPercent}%</span>
        )}

        <button 
          className="wishlist-btn"
          onClick={handleWishlistToggle}
          aria-label={isInWishlist(product._id) ? 'Remove from wishlist' : 'Add to wishlist'}
        >
          <Heart fill={isInWishlist(product._id) ? 'red' : 'white'} />
        </button>
      </div>

      <div className="product-info">
        <Link to={`/product/${product._id}`} className="product-name">
          <h3>{product.name}</h3>
        </Link>

        <div className="product-rating">
          <div className="stars">
            {[...Array(5)].map((_, i) => (
              <Star 
                key={i} 
                size={16} 
                fill={i < Math.floor(product.ratings.average) ? '#FFD700' : '#E5E7EB'}
              />
            ))}
          </div>
          <span className="rating-count">({product.ratings.count})</span>
        </div>

        <div className="product-price">
          <span className="final-price">${finalPrice.toFixed(2)}</span>
          {product.discountPrice && (
            <span className="original-price">${product.price.toFixed(2)}</span>
          )}
        </div>

        <div className="product-stock">
          {product.stock > 0 ? (
            <span className="in-stock">In Stock ({product.stock} left)</span>
          ) : (
            <span className="out-of-stock">Out of Stock</span>
          )}
        </div>

        <button
          className="add-to-cart-btn"
          onClick={handleAddToCart}
          disabled={product.stock === 0}
        >
          <ShoppingCart size={20} />
          {product.stock > 0 ? 'Add to Cart' : 'Out of Stock'}
        </button>
      </div>
    </div>
  );
};

export default ProductCard;

